export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:20。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務安全區。走廊盡頭的塑膠椅。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐下來。不是因為想坐。是因為站務人員叫她等一下。最後一份表格還沒填完。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "剛才她站在站外。風很大。手機震動——琴音來訊。她回了六個字，正要收進口袋，被叫回來繼續走流程。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個站務人員拿著手機走近。不是打電話。是拍照。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "請把手伸出來。掌心朝上。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她伸出手。血乾在指縫裡，暗褐色的細線從指節爬到手腕。閃光燈亮了一下。又一下。手背。掌心。袖口。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "外套袖口先不要洗。之後可能要確認。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我知道。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著自己的袖口。深色的布料上有一塊更深的痕跡。已經乾了。已經變成布的一部分。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務人員遞過來一包濕紙巾。她抽了兩張，擦掌心。擦不掉全部。血的味道留在皮膚紋路裡。她聞得到。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。也是滿手血。那時候我拿著銀色外殼。被整理成持尖銳物者。這一輪我沒拿外殼。但血還是在。只是換了來源。不是千田胸口的血。是我替他壓住傷口時沾上的。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "另一個站務人員走過來。手裡拿著那份表格。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "還有個問題沒問。妳為什麼不先叫站務人員？", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著他。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "妳看到有人把傷者帶進施工通道。正常人會先找站務。妳為什麼直接跟進去？", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯因為上一輪他死在第七車裡。因為我知道如果等站務走流程，他會在通道裡被殺完。因為我記得循環。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我來不及想那麼多。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務人員看了她一會兒。在表格上寫了什麼。沒有追問。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊另一端傳來聲音。救護人員和站務在交接。聲音不大，但走廊安靜，字字清楚。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Paramedic, character: "救護人員", dialogue: "搬送先——灣岸中央急救醫療中心。已經聯絡急診。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯灣岸中央。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有抬頭。沒有看那邊。手指在膝蓋上收緊了一下。然後鬆開。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是公開資訊。是救護和站務在現場說的。只有站在這裡、在這個時間、聽到這句話的人才知道。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從口袋裡摸出一張紙。濕紙巾的包裝紙。背面是空白的。她用指甲在上面壓。沒有筆。她用力摺，讓摺痕變成字的形狀。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯灣岸中央急救醫療中心。寫在紙上。不留在手機裡——手機會被看，備忘錄也會被看。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來，塞進外套內袋。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機在口袋裡。螢幕暗著。她剛才發出去的那條訊息還停在對話框裡。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "我沒事，晚點說。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯已送達。已讀。琴音沒有再回。六個字。沒有醫院名字。沒有千田還活著。就夠了。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務人員收走表格。朝她點了一下頭。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "可以了。從那邊出去。手機保持開機。明天上午去警局做筆錄。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他頓了一下。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "這還沒結束。現場還要封鎖，救護車也還要處理。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯好。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。椅子沒有聲音。她走向出口。", background: Background.Chapter_7_Ch7_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯重要目擊者。不是嫌疑人。入口影像拍到我在千田和維修人員之後進入。我主動通報。我做了止血壓迫。側門門禁有異常。讀卡紀錄指向第三者。這些加起來，夠讓我暫時走出去。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但每一步都像踩在未來的問話紀錄上。", background: Background.Chapter_7_Ch7_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她經過月台。", background: Background.Chapter_7_Ch7_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第七車在那裡。門開著。燈亮著。幾個乘客在上下車。沒有封鎖線。沒有鑑識人員。沒有白色布蓋住什麼東西。", background: Background.Chapter_7_Ch7_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "月台在運作。像什麼都沒發生過。", background: Background.Chapter_7_Ch7_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。這裡有屍體。有封鎖線。有鑑識。有我站在車廂裡拿著外殼的畫面。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第二輪。什麼都沒有。月台在運作。列車在開。乘客在上下車。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這本該是勝利。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那扇開著的車門。燈光從車廂裡照出來，落在月台地面上，方方正正的一塊光。一個乘客走進去。門關了。車開了。", background: Background.Chapter_7_Ch7_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但這不是勝利。這是一種更不安的空白。死亡沒有發生在這裡。它只是換了地址。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出站務出口。夜風從灣岸方向吹過來。她的手在口袋裡。右手碰著那張摺起來的紙。左手碰著小鏡子的布套。", background: Background.Chapter_7_Ch7_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯去醫院。不是探病。是確認三件事。千田是否仍活著。病人物袋是否存在。外殼是否被轉走。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯灣岸中央急救醫療中心。", background: Background.Chapter_7_Ch7_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向灣岸道路。救護車早就消失了。但方向她記得。", background: Background.Chapter_7_Ch7_Act1_S1 },
];
